--
-- Table structure for table `imovel`
--

DROP TABLE IF EXISTS `imovel`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `imovel` (
  `id_imovel` int NOT NULL AUTO_INCREMENT,
  `morada` varchar(150) NOT NULL,
  `data_anuncio` datetime DEFAULT CURRENT_TIMESTAMP,
  `preco` decimal(12,2) DEFAULT NULL,
  `descricao` varchar(9999) DEFAULT NULL,
  `numero_quartos` int unsigned DEFAULT '0',
  `numero_wc` int unsigned DEFAULT '0',
  `data_construcao` date DEFAULT NULL,
  `area` decimal(6,2) NOT NULL,
  `id_anunciante` int NOT NULL,
  `id_freguesia` varchar(9) NOT NULL,
  `imagem_principal` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id_imovel`),
  KEY `id_anunciante` (`id_anunciante`),
  KEY `id_freguesia` (`id_freguesia`),
  CONSTRAINT `imovel_ibfk_1` FOREIGN KEY (`id_anunciante`) REFERENCES `anunciante` (`id_anunciante`)
) ENGINE=InnoDB AUTO_INCREMENT=413 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
